(function(){var e=document.querySelectorAll(".day-tab"),t=document.querySelectorAll(".day-panel");e.length&&e.forEach(function(n){n.addEventListener("click",function(){var s=n.getAttribute("data-day");e.forEach(function(e){e.classList.toggle("is-active",e===n)}),t.forEach(function(e){e.classList.toggle("is-active",e.getAttribute("data-day")===s)})})}),document.querySelectorAll(".schedule-item.has-details").forEach(function(e){var t=e.querySelector(".schedule-row"),n=e.querySelector(".schedule-panel");t.addEventListener("click",function(){var s=e.classList.toggle("is-open");t.setAttribute("aria-expanded",s?"true":"false"),n.style.maxHeight=s?n.scrollHeight+"px":"0px"})})})()